import functions_framework
import hmac
import hashlib
import json
import os
from flask import jsonify

WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET', 'your-secret-key-here')

def verify_signature(payload, signature, secret):
    """Verify HMAC signature of the webhook payload"""
    if not signature:
        return False
    
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        payload.encode('utf-8'),
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_payment_event(data):
    """Validate payment event structure"""
    required_fields = ['event_type', 'transaction_id', 'amount', 'timestamp']
    
    if not all(field in data for field in required_fields):
        return False, "Missing required fields"
    
    valid_event_types = ['payment.success', 'payment.failed', 'payment.pending', 'refund.processed']
    if data['event_type'] not in valid_event_types:
        return False, "Invalid event type"
    
    try:
        amount = float(data['amount'])
        if amount < 0:
            return False, "Invalid amount"
    except (ValueError, TypeError):
        return False, "Invalid amount format"
    
    return True, None

def process_payment_event(data):
    """Process the validated payment event"""
    event_type = data['event_type']
    transaction_id = data['transaction_id']
    amount = data['amount']
    
    print(f"Processing {event_type} for transaction {transaction_id}, amount: {amount}")
    
    if event_type == 'payment.success':
        print(f"Payment successful: {transaction_id}")
    elif event_type == 'payment.failed':
        print(f"Payment failed: {transaction_id}")
    elif event_type == 'payment.pending':
        print(f"Payment pending: {transaction_id}")
    elif event_type == 'refund.processed':
        print(f"Refund processed: {transaction_id}")
    
    return {
        'status': 'processed',
        'transaction_id': transaction_id,
        'event_type': event_type
    }

@functions_framework.http
def webhook_handler(request):
    """HTTP Cloud Function for processing payment webhooks"""
    
    if request.method != 'POST':
        return jsonify({'error': 'Method not allowed'}), 405
    
    signature = request.headers.get('X-Webhook-Signature', '')
    
    try:
        payload = request.get_data(as_text=True)
        
        if not verify_signature(payload, signature, WEBHOOK_SECRET):
            print("Invalid signature")
            return jsonify({'error': 'Invalid signature'}), 401
        
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'Invalid JSON payload'}), 400
        
        is_valid, error_message = validate_payment_event(data)
        if not is_valid:
            print(f"Validation error: {error_message}")
            return jsonify({'error': error_message}), 400
        
        result = process_payment_event(data)
        
        return jsonify(result), 200
        
    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON'}), 400
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500